@namespace Lumeo

@if (Label is not null && !InsideFormField)
{
    <label class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ml-0.5">*</span>
        }
    </label>
}

<Popover @bind-Open="_isOpen">
    <PopoverTrigger>
        <button type="button"
                name="@Name"
                aria-required="@Required.ToString().ToLower()"
                aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                class="@CssClass"
                disabled="@Disabled"
                @attributes="AdditionalAttributes">
            <Blazicon Svg="Lucide.Calendar" class="mr-2 h-4 w-4 shrink-0" />
            @if (Value.HasValue)
            {
                <span>@FormatDateTime(Value.Value)</span>
                @if (ShowTimeZoneLabel && TimeZone is not null)
                {
                    <span class="ml-2 text-xs text-muted-foreground">@FormatZoneLabel(Value.Value)</span>
                }
            }
            else
            {
                <span class="text-muted-foreground group-hover:text-accent-foreground">@EffectivePlaceholder</span>
            }
            @if (Clearable && Value.HasValue)
            {
                <button type="button" class="ml-auto pl-1 hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded" aria-label="@L["DateTimePicker.ClearDate"]" @onclick="HandleClear" @onclick:stopPropagation="true">
                    <Blazicon Svg="Lucide.X" class="h-3.5 w-3.5" />
                </button>
            }
        </button>
    </PopoverTrigger>
    <PopoverContent Align="Lumeo.Align.Start" Class="w-auto p-0">
        <div class="flex">
            <div>
                <Calendar Value="@_dateValue" ValueChanged="HandleDateChanged"
                  MinDate="@(MinDate.HasValue ? (DateOnly?)DateOnly.FromDateTime(MinDate.Value) : null)"
                  MaxDate="@(MaxDate.HasValue ? (DateOnly?)DateOnly.FromDateTime(MaxDate.Value) : null)"
                  IsDateDisabled="@IsDateDisabled"
                  FirstDayOfWeek="@FirstDayOfWeek" />
            </div>
            <div class="border-l border-border/40">
                <div class="p-3 pb-1">
                    <span class="text-xs font-medium text-muted-foreground">@L["DateTimePicker.TimeLabel"]</span>
                </div>
                <div class="flex divide-x divide-border/40">
                    @* Hours column *@
                    <div id="@_hoursColId" role="listbox" aria-label="@L["TimePicker.HoursLabel"]" class="flex flex-col h-[240px] overflow-y-auto py-1 scrollbar-thin">
                        @{ var hours = GetHours(); }
                        @foreach (var hour in hours)
                        {
                            var h = hour;
                            var isSelected = _timeValue.HasValue && GetDisplayHour(_timeValue.Value) == h;
                            var disabled = IsHourDisabled(h);
                            <button type="button" id="@ColItemId(_hoursColId, h)" role="option"
                                    aria-selected="@(isSelected ? "true" : "false")"
                                    tabindex="@(isSelected ? "0" : "-1")"
                                    disabled="@disabled"
                                    class="@TimeItemClass(isSelected)"
                                    @onclick="() => SelectHour(h)"
                                    @onkeydown="e => HandleColumnKeyDown(e, _hoursColId, hours, h)">
                                @h.ToString("D2")
                            </button>
                        }
                    </div>

                    @* Minutes column *@
                    <div id="@_minutesColId" role="listbox" aria-label="@L["TimePicker.MinutesLabel"]" class="flex flex-col h-[240px] overflow-y-auto py-1 scrollbar-thin">
                        @{ var minutes = GetMinutes(); }
                        @foreach (var minute in minutes)
                        {
                            var m = minute;
                            var isSelected = _timeValue.HasValue && _timeValue.Value.Minutes == m;
                            var disabled = IsMinuteDisabled(m);
                            <button type="button" id="@ColItemId(_minutesColId, m)" role="option"
                                    aria-selected="@(isSelected ? "true" : "false")"
                                    tabindex="@(isSelected ? "0" : "-1")"
                                    disabled="@disabled"
                                    class="@TimeItemClass(isSelected)"
                                    @onclick="() => SelectMinute(m)"
                                    @onkeydown="e => HandleColumnKeyDown(e, _minutesColId, minutes, m)">
                                @m.ToString("D2")
                            </button>
                        }
                    </div>

                    @* Seconds column *@
                    @if (ShowSeconds)
                    {
                        <div id="@_secondsColId" role="listbox" aria-label="@L["TimePicker.SecondsLabel"]" class="flex flex-col h-[240px] overflow-y-auto py-1 scrollbar-thin">
                            @{ var seconds = GetSeconds(); }
                            @foreach (var second in seconds)
                            {
                                var s = second;
                                var isSelected = _timeValue.HasValue && _timeValue.Value.Seconds == s;
                                var disabled = IsSecondDisabled(s);
                                <button type="button" id="@ColItemId(_secondsColId, s)" role="option"
                                        aria-selected="@(isSelected ? "true" : "false")"
                                        tabindex="@(isSelected ? "0" : "-1")"
                                        disabled="@disabled"
                                        class="@TimeItemClass(isSelected)"
                                        @onclick="() => SelectSecond(s)"
                                        @onkeydown="e => HandleColumnKeyDown(e, _secondsColId, seconds, s)">
                                    @s.ToString("D2")
                                </button>
                            }
                        </div>
                    }

                    @* AM/PM column *@
                    @if (!Use24Hour)
                    {
                        <div class="flex flex-col py-1">
                            @{
                                var isAm = !_timeValue.HasValue || _timeValue.Value.Hours < 12;
                                var amLabel = string.IsNullOrEmpty(EffectiveCulture.DateTimeFormat.AMDesignator) ? "AM" : EffectiveCulture.DateTimeFormat.AMDesignator;
                                var pmLabel = string.IsNullOrEmpty(EffectiveCulture.DateTimeFormat.PMDesignator) ? "PM" : EffectiveCulture.DateTimeFormat.PMDesignator;
                            }
                            <button type="button"
                                    class="@TimeItemClass(isAm)"
                                    @onclick="() => SelectAmPm(true)">
                                @amLabel
                            </button>
                            <button type="button"
                                    class="@TimeItemClass(!isAm)"
                                    @onclick="() => SelectAmPm(false)">
                                @pmLabel
                            </button>
                        </div>
                    }
                </div>
            </div>
        </div>
    </PopoverContent>
</Popover>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}

@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject Lumeo.Services.IComponentInteropService Interop

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    [Parameter] public DateTime? Value { get; set; }
    [Parameter] public EventCallback<DateTime?> ValueChanged { get; set; }

    /// <summary>
    /// Optional <see cref="DateTimeOffset"/> binding. When the caller binds this,
    /// it takes precedence: writes flow back through <see cref="OffsetValueChanged"/>
    /// with the offset that matches <see cref="TimeZone"/> at the picked wall-clock
    /// time (DST-aware). The plain <see cref="ValueChanged"/> still fires for back-compat.
    /// Recommended over <see cref="Value"/> when working with multi-zone scenarios.
    /// </summary>
    [Parameter] public DateTimeOffset? OffsetValue { get; set; }
    [Parameter] public EventCallback<DateTimeOffset?> OffsetValueChanged { get; set; }

    /// <summary>
    /// When non-null, all display/edit happens in this zone — the user picks a
    /// wall-clock instant in that zone, and the emitted <see cref="DateTimeOffset"/>
    /// carries the matching offset for that instant (DST-aware). When null, the
    /// picker behaves exactly as before (local time, no zone indicator).
    /// </summary>
    [Parameter] public TimeZoneInfo? TimeZone { get; set; }

    /// <summary>
    /// When true (default) and <see cref="TimeZone"/> is set, renders a small
    /// "Europe/Berlin (UTC+1)"-style indicator next to the value.
    /// </summary>
    [Parameter] public bool ShowTimeZoneLabel { get; set; } = true;

    [Parameter] public bool Use24Hour { get; set; } = true;
    [Parameter] public bool ShowSeconds { get; set; }
    /// <summary>Minute column increment. <c>1</c> (default) lists every minute;
    /// <c>5</c>/<c>15</c> etc. list only multiples of the step.</summary>
    [Parameter] public int MinuteStep { get; set; } = 1;
    /// <summary>Second column increment (only relevant when <see cref="ShowSeconds"/>
    /// is true). Defaults to <c>1</c>.</summary>
    [Parameter] public int SecondStep { get; set; } = 1;
    /// <summary>
    /// Date portion format. When null (default) falls back to the effective culture's
    /// <c>ShortDatePattern</c>.
    /// </summary>
    [Parameter] public string? DateFormat { get; set; }
    [Parameter] public string? Placeholder { get; set; }

    /// <summary>
    /// Overrides <see cref="System.Globalization.CultureInfo.CurrentCulture"/> for
    /// date/time formatting. Leave null to honour ASP.NET request localization.
    /// </summary>
    [Parameter] public System.Globalization.CultureInfo? Culture { get; set; }

    private System.Globalization.CultureInfo EffectiveCulture => Culture ?? System.Globalization.CultureInfo.CurrentCulture;
    private string EffectiveDateFormat => DateFormat ?? EffectiveCulture.DateTimeFormat.ShortDatePattern;

    private string EffectivePlaceholder => Placeholder ?? L["DateTimePicker.Placeholder"];
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool Clearable { get; set; }
    [Parameter] public DateTime? MinDate { get; set; }
    [Parameter] public DateTime? MaxDate { get; set; }
    [Parameter] public Func<DateTime, bool>? IsDateDisabled { get; set; }
    /// <summary>
    /// Override the locale-derived first day of week shown by the embedded calendar.
    /// Forwarded to the inner <see cref="Calendar"/>; leave null to fall back to
    /// <see cref="System.Globalization.CultureInfo.CurrentCulture"/>.
    /// </summary>
    [Parameter] public DayOfWeek? FirstDayOfWeek { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _isOpen;
    private DateOnly? _dateValue;
    private TimeSpan? _timeValue;
    private DateTime? _prevValue;
    private DateTimeOffset? _prevOffsetValue;

    private string CssClass => Cx.Merge("group flex h-9 w-full items-center rounded-md border", (EffectiveInvalid ? "border-destructive ring-1 ring-destructive/20" : "border-input"), "bg-transparent px-3 py-2 text-sm shadow-sm hover:bg-accent hover:text-accent-foreground disabled:cursor-not-allowed disabled:opacity-50", Class);

    protected override void OnParametersSet()
    {
        // When the parent binds OffsetValue and it changed, derive Value from it
        // by projecting into the configured TimeZone (or local if null).
        if (OffsetValue != _prevOffsetValue)
        {
            _prevOffsetValue = OffsetValue;
            if (OffsetValue.HasValue)
            {
                var local = TimeZone is null
                    ? OffsetValue.Value.LocalDateTime
                    : TimeZoneInfo.ConvertTime(OffsetValue.Value, TimeZone).DateTime;
                Value = DateTime.SpecifyKind(local, DateTimeKind.Unspecified);
            }
            else
            {
                Value = null;
            }
        }

        // Resync the internal date/time selection only when the bound Value
        // actually changed. A time picked before any date lives solely in
        // _timeValue (UpdateValue can't commit without a date) — resyncing
        // unconditionally meant any parent re-render wiped that pending
        // selection back to the (null) Value.
        if (Value != _prevValue)
        {
            _prevValue = Value;
            if (Value.HasValue)
            {
                _dateValue = DateOnly.FromDateTime(Value.Value);
                _timeValue = Value.Value.TimeOfDay;
            }
            else
            {
                _dateValue = null;
                _timeValue = null;
            }
        }
    }

    private string FormatZoneLabel(DateTime wallClock)
    {
        if (TimeZone is null) return string.Empty;
        var unspecified = DateTime.SpecifyKind(wallClock, DateTimeKind.Unspecified);
        var offset = TimeZone.GetUtcOffset(unspecified);
        var sign = offset.Ticks >= 0 ? "+" : "-";
        var abs = offset.Duration();
        var offsetText = abs.Minutes == 0
            ? $"UTC{sign}{abs.Hours}"
            : $"UTC{sign}{abs.Hours}:{abs.Minutes:D2}";
        return $"{TimeZone.Id} ({offsetText})";
    }

    private DateTimeOffset? ToOffset(DateTime? wallClock)
    {
        if (!wallClock.HasValue) return null;
        var unspecified = DateTime.SpecifyKind(wallClock.Value, DateTimeKind.Unspecified);
        if (TimeZone is null)
        {
            // Treat as local — preserve historic behaviour.
            return new DateTimeOffset(DateTime.SpecifyKind(wallClock.Value, DateTimeKind.Local));
        }
        var offset = TimeZone.GetUtcOffset(unspecified);
        return new DateTimeOffset(unspecified, offset);
    }

    private string FormatDateTime(DateTime dt)
    {
        var timeFormat = Use24Hour
            ? (ShowSeconds ? "HH:mm:ss" : "HH:mm")
            : (ShowSeconds ? "hh:mm:ss tt" : "hh:mm tt");
        return $"{dt.ToString(EffectiveDateFormat, EffectiveCulture)} {dt.ToString(timeFormat, EffectiveCulture)}";
    }

    private List<int> GetHours()
    {
        var hours = new List<int>();
        if (Use24Hour)
        {
            for (var i = 0; i < 24; i++) hours.Add(i);
        }
        else
        {
            for (var i = 1; i <= 12; i++) hours.Add(i);
        }
        return hours;
    }

    private int GetDisplayHour(TimeSpan time)
    {
        if (Use24Hour) return time.Hours;
        var h = time.Hours % 12;
        return h == 0 ? 12 : h;
    }

    private List<int> GetMinutes()
    {
        var minutes = new List<int>();
        var step = Math.Max(1, MinuteStep);
        for (var i = 0; i < 60; i += step) minutes.Add(i);
        return minutes;
    }

    private List<int> GetSeconds()
    {
        var seconds = new List<int>();
        var step = Math.Max(1, SecondStep);
        for (var i = 0; i < 60; i += step) seconds.Add(i);
        return seconds;
    }

    private static string TimeItemClass(bool isSelected) =>
        isSelected
            ? "px-3 py-1.5 text-sm cursor-pointer bg-primary text-primary-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 disabled:pointer-events-none disabled:opacity-40"
            : "px-3 py-1.5 text-sm cursor-pointer hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:bg-muted/50 disabled:pointer-events-none disabled:opacity-40";

    // ---- Date-aware Min/Max enforcement on the time columns (#208) ----
    // The bounds only bite on the boundary day: if the selected date equals
    // MinDate's date, times before MinDate's time-of-day are disabled; likewise
    // MaxDate caps the time on its date. On days strictly inside the range the
    // whole clock is selectable. With no date picked yet we can't know which
    // day applies, so nothing is disabled (the calendar already gates the date).
    private TimeSpan? MinTimeForSelectedDate
    {
        get
        {
            if (!MinDate.HasValue || !_dateValue.HasValue) return null;
            return _dateValue.Value == DateOnly.FromDateTime(MinDate.Value) ? MinDate.Value.TimeOfDay : null;
        }
    }

    private TimeSpan? MaxTimeForSelectedDate
    {
        get
        {
            if (!MaxDate.HasValue || !_dateValue.HasValue) return null;
            return _dateValue.Value == DateOnly.FromDateTime(MaxDate.Value) ? MaxDate.Value.TimeOfDay : null;
        }
    }

    private bool IsHourDisabled(int displayHour)
    {
        var h24 = DisplayHourTo24(displayHour);
        var hourStart = new TimeSpan(h24, 0, 0);
        var hourEnd = new TimeSpan(h24, 59, ShowSeconds ? 59 : 0);
        var min = MinTimeForSelectedDate;
        var max = MaxTimeForSelectedDate;
        if (min.HasValue && hourEnd < min.Value) return true;
        if (max.HasValue && hourStart > max.Value) return true;
        return false;
    }

    private bool IsMinuteDisabled(int minute)
    {
        var h = (_timeValue ?? TimeSpan.Zero).Hours;
        var minStart = new TimeSpan(0, h, minute, 0);
        var minEnd = new TimeSpan(0, h, minute, ShowSeconds ? 59 : 0);
        var min = MinTimeForSelectedDate;
        var max = MaxTimeForSelectedDate;
        if (min.HasValue && minEnd < min.Value) return true;
        if (max.HasValue && minStart > max.Value) return true;
        return false;
    }

    private bool IsSecondDisabled(int second)
    {
        var current = _timeValue ?? TimeSpan.Zero;
        var candidate = new TimeSpan(0, current.Hours, current.Minutes, second);
        var min = MinTimeForSelectedDate;
        var max = MaxTimeForSelectedDate;
        if (min.HasValue && candidate < min.Value) return true;
        if (max.HasValue && candidate > max.Value) return true;
        return false;
    }

    private int DisplayHourTo24(int displayHour)
    {
        if (Use24Hour) return displayHour;
        var isPm = (_timeValue ?? TimeSpan.Zero).Hours >= 12;
        var h = displayHour % 12;
        return isPm ? h + 12 : h;
    }

    private async Task HandleDateChanged(DateOnly? date)
    {
        _dateValue = date;
        await UpdateValue();
    }

    private async Task SelectHour(int hour)
    {
        if (IsHourDisabled(hour)) return;
        var current = _timeValue ?? TimeSpan.Zero;
        int actualHour;
        if (Use24Hour)
        {
            actualHour = hour;
        }
        else
        {
            var isPm = current.Hours >= 12;
            actualHour = hour % 12;
            if (isPm) actualHour += 12;
        }
        _timeValue = new TimeSpan(actualHour, current.Minutes, current.Seconds);
        await UpdateValue();
    }

    private async Task SelectMinute(int minute)
    {
        if (IsMinuteDisabled(minute)) return;
        var current = _timeValue ?? TimeSpan.Zero;
        _timeValue = new TimeSpan(current.Hours, minute, current.Seconds);
        await UpdateValue();
    }

    private async Task SelectSecond(int second)
    {
        if (IsSecondDisabled(second)) return;
        var current = _timeValue ?? TimeSpan.Zero;
        _timeValue = new TimeSpan(current.Hours, current.Minutes, second);
        await UpdateValue();
    }

    private async Task SelectAmPm(bool isAm)
    {
        var current = _timeValue ?? TimeSpan.Zero;
        var hour = current.Hours % 12;
        if (!isAm) hour += 12;
        _timeValue = new TimeSpan(hour, current.Minutes, current.Seconds);
        await UpdateValue();
    }

    // ---- Arrow-key list navigation (roving focus per time column) ----
    // Mirrors TimePicker so the DateTimePicker's time columns are keyboard-navigable
    // too: ArrowDown/Up move to the next/previous ENABLED option, Home/End jump to
    // the first/last enabled option, Enter/Space select. The arrow keys' page/column
    // scroll is suppressed via the prevent-default registration below.
    private readonly string _hoursColId = LumeoIds.New("dtp-hours");
    private readonly string _minutesColId = LumeoIds.New("dtp-minutes");
    private readonly string _secondsColId = LumeoIds.New("dtp-seconds");

    private static string ColItemId(string colId, int value) => $"{colId}-{value}";

    private async Task HandleColumnKeyDown(KeyboardEventArgs e, string colId, List<int> values, int current)
    {
        switch (e.Key)
        {
            case "ArrowDown": await FocusAdjacent(colId, values, current, +1); break;
            case "ArrowUp": await FocusAdjacent(colId, values, current, -1); break;
            case "Home": await FocusEdge(colId, values, fromStart: true); break;
            case "End": await FocusEdge(colId, values, fromStart: false); break;
            case "Enter":
            case " ":
                await SelectForColumn(colId, current);
                break;
        }
    }

    private async Task FocusAdjacent(string colId, List<int> values, int current, int step)
    {
        var idx = values.IndexOf(current);
        if (idx < 0) return;
        for (var i = idx + step; i >= 0 && i < values.Count; i += step)
        {
            if (!IsColItemDisabled(colId, values[i]))
            {
                await Interop.FocusElement(ColItemId(colId, values[i]));
                return;
            }
        }
    }

    private async Task FocusEdge(string colId, List<int> values, bool fromStart)
    {
        var ordered = fromStart ? values : Enumerable.Reverse(values).ToList();
        foreach (var v in ordered)
        {
            if (!IsColItemDisabled(colId, v))
            {
                await Interop.FocusElement(ColItemId(colId, v));
                return;
            }
        }
    }

    private bool IsColItemDisabled(string colId, int value)
    {
        if (colId == _hoursColId) return IsHourDisabled(value);
        if (colId == _minutesColId) return IsMinuteDisabled(value);
        if (colId == _secondsColId) return IsSecondDisabled(value);
        return false;
    }

    private Task SelectForColumn(string colId, int value)
    {
        if (colId == _hoursColId) return SelectHour(value);
        if (colId == _minutesColId) return SelectMinute(value);
        if (colId == _secondsColId) return SelectSecond(value);
        return Task.CompletedTask;
    }

    private bool _navKeysRegistered;
    private static readonly PreventDefaultKeyRule[] ColumnNavKeys =
    [
        new("ArrowUp"), new("ArrowDown"), new("Home"), new("End"),
    ];

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_isOpen && !_navKeysRegistered)
        {
            _navKeysRegistered = true;
            try
            {
                await Interop.RegisterPreventDefaultKeys(_hoursColId, ColumnNavKeys);
                await Interop.RegisterPreventDefaultKeys(_minutesColId, ColumnNavKeys);
                if (ShowSeconds) await Interop.RegisterPreventDefaultKeys(_secondsColId, ColumnNavKeys);
            }
            catch (JSDisconnectedException) { _navKeysRegistered = false; }
            catch (InvalidOperationException) { _navKeysRegistered = false; } // prerender
        }
        else if (!_isOpen && _navKeysRegistered)
        {
            _navKeysRegistered = false;
            try
            {
                await Interop.UnregisterPreventDefaultKeys(_hoursColId);
                await Interop.UnregisterPreventDefaultKeys(_minutesColId);
                if (ShowSeconds) await Interop.UnregisterPreventDefaultKeys(_secondsColId);
            }
            catch (JSDisconnectedException) { }
        }
    }

    private async Task UpdateValue()
    {
        if (_dateValue.HasValue)
        {
            var time = _timeValue ?? TimeSpan.Zero;
            var dt = _dateValue.Value.ToDateTime(new TimeOnly(time.Hours, time.Minutes, time.Seconds));
            // When a TimeZone is configured, the wall-clock value is zone-relative —
            // mark it Unspecified so callers don't mistake it for system-local.
            if (TimeZone is not null) dt = DateTime.SpecifyKind(dt, DateTimeKind.Unspecified);
            Value = dt;
            _prevValue = dt;
            await ValueChanged.InvokeAsync(dt);

            if (OffsetValueChanged.HasDelegate)
            {
                var offset = ToOffset(dt);
                _prevOffsetValue = offset;
                await OffsetValueChanged.InvokeAsync(offset);
            }
        }
    }

    private async Task HandleClear()
    {
        Value = null;
        _prevValue = null;
        _dateValue = null;
        _timeValue = null;
        await ValueChanged.InvokeAsync(null);
        if (OffsetValueChanged.HasDelegate)
        {
            _prevOffsetValue = null;
            await OffsetValueChanged.InvokeAsync(null);
        }
    }
}
